import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"157. Shift Work Allowances","description":"","frontmatter":{"title":"157. Shift Work Allowances","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/157-shift-work-allowances.md","filePath":"ebas/mental-health/support-services/preliminary/157-shift-work-allowances.md"}'),r={name:"ebas/mental-health/support-services/preliminary/157-shift-work-allowances.md"};function s(i,e,h,l,c,d){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_157-shift-work-allowances" tabindex="-1">157. Shift Work Allowances <a class="header-anchor" href="#_157-shift-work-allowances" aria-label="Permalink to &quot;157. Shift Work Allowances&quot;">​</a></h1><p><strong>157.1</strong> Definitions In this clause 157:</p><p><strong>(a)</strong> Morning shift means any shift that commences between 6:00 p.m. and 6:30 a.m.</p><p><strong>(b)</strong> Afternoon shift means any shift that finishes between 6:00 p.m. and 8:00 a.m.</p><p><strong>(c)</strong> Night shift means any shift that finishes on the day after commencing duty or commences after midnight and before 5:00 a.m.</p><p><strong>(d)</strong> Sunday night shift means a shift worked by a full-time or part-time Employee that commences on Sunday and concludes on Monday.</p><p><strong>(e)</strong> Permanent night shift Employee means an Employee permanently working on any such rostered hours of ordinary night duty for any period in excess of four consecutive weeks.</p><p><strong>157.2</strong> Application</p><p><strong>(a)</strong> Where a shift meets more than one definition as set out in 157.1, the Employee be paid one shift allowance only, with the higher shift allowance where the rates differ.</p><p><strong>157.3</strong> Shift Allowances In addition to any other rates prescribed elsewhere in this Agreement, the Employee will receive the following allowances where an Employee works:</p><p><strong>(a)</strong> A Morning Shift, an allowance set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty</p><p><strong>(b)</strong> An Afternoon Shift, an amount set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty</p><p><strong>(c)</strong> A Temporary Night Shift</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per period of duty.</p><p><strong>(ii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Weekday Night Duty’ for each period of duty commencing on a Monday, Tuesday, Wednesday or Thursday’.</p><p><strong>(iii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Fri/Sat Night Duty’ for each period of duty commencing on a Friday or Saturday.</p><p><strong>(iv)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Sun Night Duty’ for each period of duty commencing on a Sunday.</p><p><strong>(d)</strong> A Permanent Night Shift</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per period of duty.</p><p><strong>(ii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Weekday Night Duty’ for each period of duty commencing on a Monday, Tuesday, Wednesday or Thursday’.</p><p><strong>(iii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Fri/Sat Night Duty’ for each period of duty commencing on a Friday or Saturday.</p><p><strong>(iv)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Sun Night Duty’ for each period of duty commencing on a Sunday.</p>',22)])])}const m=a(r,[["render",s]]);export{f as __pageData,m as default};
